async function testGetWeatherValidation() {
  // Test missing parameters — should return 400
  const res1 = await fetch('/api/weather');
  assertEquals(res1.status, 400, 'Missing params should return 400');
  const body1 = await res1.json();
  assert(body1.error === true, 'Should have error flag');
  assert(body1.message.includes('required'), 'Should mention required params');

  // Test missing lon — should return 400
  const res2 = await fetch('/api/weather?lat=43.3');
  assertEquals(res2.status, 400, 'Missing lon should return 400');

  // Test invalid lat — out of range
  const res3 = await fetch('/api/weather?lat=200&lon=5');
  assertEquals(res3.status, 400, 'Out of range lat should return 400');
  const body3 = await res3.json();
  assert(body3.message.includes('Invalid'), 'Should mention invalid coordinates');

  // Test non-numeric params
  const res4 = await fetch('/api/weather?lat=abc&lon=xyz');
  assertEquals(res4.status, 400, 'Non-numeric params should return 400');
}
